using Microsoft.VisualStudio.TestTools.UnitTesting;
using Store;

namespace Store.Tests;

[TestClass]
public class ShoppingCartTests
{
    private ShoppingCart _cart = null!;

    [TestInitialize]
    public void Setup() => _cart = new ShoppingCart();

    // ───────── AddItem ─────────

    [TestMethod]
    public void AddItem_SingleItem_AppearsInCart()
    {
        _cart.AddItem("SKU-1", 2, 9.99m);

        Assert.IsTrue(_cart.Items.ContainsKey("SKU-1"));
        Assert.AreEqual(2, _cart.Items["SKU-1"].Quantity);
        Assert.AreEqual(9.99m, _cart.Items["SKU-1"].Price);
    }

    [TestMethod]
    public void AddItem_SameSkuTwice_QuantitiesAccumulate()
    {
        _cart.AddItem("SKU-1", 1, 5.00m);
        _cart.AddItem("SKU-1", 3, 5.00m);

        Assert.AreEqual(4, _cart.Items["SKU-1"].Quantity);
    }

    [TestMethod]
    public void AddItem_SameSkuTwice_PriceUpdatesToLatest()
    {
        _cart.AddItem("SKU-1", 1, 5.00m);
        _cart.AddItem("SKU-1", 1, 7.00m);

        Assert.AreEqual(7.00m, _cart.Items["SKU-1"].Price);
    }

    [TestMethod]
    public void AddItem_MultipleDistinctItems_AllPresent()
    {
        _cart.AddItem("A", 1, 1.00m);
        _cart.AddItem("B", 2, 2.00m);
        _cart.AddItem("C", 3, 3.00m);

        Assert.AreEqual(3, _cart.Items.Count);
    }

    [TestMethod]
    [ExpectedException(typeof(ArgumentException))]
    public void AddItem_NullSku_Throws() => _cart.AddItem(null!, 1, 1.00m);

    [TestMethod]
    [ExpectedException(typeof(ArgumentException))]
    public void AddItem_EmptySku_Throws() => _cart.AddItem("", 1, 1.00m);

    [TestMethod]
    [ExpectedException(typeof(ArgumentException))]
    public void AddItem_WhitespaceSku_Throws() => _cart.AddItem("   ", 1, 1.00m);

    [TestMethod]
    [ExpectedException(typeof(ArgumentOutOfRangeException))]
    public void AddItem_ZeroQuantity_Throws() => _cart.AddItem("SKU-1", 0, 1.00m);

    [TestMethod]
    [ExpectedException(typeof(ArgumentOutOfRangeException))]
    public void AddItem_NegativeQuantity_Throws() => _cart.AddItem("SKU-1", -1, 1.00m);

    [TestMethod]
    [ExpectedException(typeof(ArgumentOutOfRangeException))]
    public void AddItem_NegativePrice_Throws() => _cart.AddItem("SKU-1", 1, -0.01m);

    [TestMethod]
    public void AddItem_ZeroPrice_Allowed()
    {
        _cart.AddItem("FREEBIE", 1, 0m);
        Assert.AreEqual(0m, _cart.Items["FREEBIE"].Price);
    }

    // ───────── RemoveItem ─────────

    [TestMethod]
    public void RemoveItem_ExistingItem_RemovesFromCart()
    {
        _cart.AddItem("SKU-1", 1, 5.00m);
        _cart.RemoveItem("SKU-1");

        Assert.AreEqual(0, _cart.Items.Count);
    }

    [TestMethod]
    [ExpectedException(typeof(KeyNotFoundException))]
    public void RemoveItem_NonExistentItem_Throws() => _cart.RemoveItem("NOPE");

    [TestMethod]
    [ExpectedException(typeof(ArgumentException))]
    public void RemoveItem_NullSku_Throws() => _cart.RemoveItem(null!);

    [TestMethod]
    public void RemoveItem_LeavesOtherItems()
    {
        _cart.AddItem("A", 1, 1.00m);
        _cart.AddItem("B", 1, 2.00m);
        _cart.RemoveItem("A");

        Assert.AreEqual(1, _cart.Items.Count);
        Assert.IsTrue(_cart.Items.ContainsKey("B"));
    }

    // ───────── CalculateTotal ─────────

    [TestMethod]
    public void CalculateTotal_EmptyCart_ReturnsZero()
    {
        Assert.AreEqual(0m, _cart.CalculateTotal());
    }

    [TestMethod]
    public void CalculateTotal_SingleItem_ReturnsCorrectTotal()
    {
        _cart.AddItem("SKU-1", 3, 10.00m);

        Assert.AreEqual(30.00m, _cart.CalculateTotal());
    }

    [TestMethod]
    public void CalculateTotal_MultipleItems_SumsCorrectly()
    {
        _cart.AddItem("A", 2, 5.00m);  // 10
        _cart.AddItem("B", 1, 3.50m);  //  3.50

        Assert.AreEqual(13.50m, _cart.CalculateTotal());
    }

    [TestMethod]
    public void CalculateTotal_AfterRemoval_Recalculates()
    {
        _cart.AddItem("A", 1, 10.00m);
        _cart.AddItem("B", 1, 20.00m);
        _cart.RemoveItem("A");

        Assert.AreEqual(20.00m, _cart.CalculateTotal());
    }

    // ───────── ApplyCoupon ─────────

    [TestMethod]
    public void ApplyCoupon_PercentOff_ReducesTotal()
    {
        _cart.AddItem("SKU-1", 1, 100.00m);
        _cart.ApplyCoupon("SAVE10");

        Assert.AreEqual(90.00m, _cart.CalculateTotal());
    }

    [TestMethod]
    public void ApplyCoupon_SAVE20_Applies20Percent()
    {
        _cart.AddItem("SKU-1", 1, 50.00m);
        _cart.ApplyCoupon("SAVE20");

        Assert.AreEqual(40.00m, _cart.CalculateTotal());
    }

    [TestMethod]
    public void ApplyCoupon_FlatDiscount_ReducesTotal()
    {
        _cart.AddItem("SKU-1", 1, 20.00m);
        _cart.ApplyCoupon("FLAT5");

        Assert.AreEqual(15.00m, _cart.CalculateTotal());
    }

    [TestMethod]
    public void ApplyCoupon_FLAT10_Subtracts10()
    {
        _cart.AddItem("SKU-1", 1, 25.00m);
        _cart.ApplyCoupon("FLAT10");

        Assert.AreEqual(15.00m, _cart.CalculateTotal());
    }

    [TestMethod]
    public void ApplyCoupon_DiscountExceedsTotal_ClampsToZero()
    {
        _cart.AddItem("SKU-1", 1, 3.00m);
        _cart.ApplyCoupon("FLAT5");

        Assert.AreEqual(0m, _cart.CalculateTotal());
    }

    [TestMethod]
    public void ApplyCoupon_MultipleCoupons_StackSequentially()
    {
        _cart.AddItem("SKU-1", 1, 100.00m);
        _cart.ApplyCoupon("SAVE10");  // 100 → 90
        _cart.ApplyCoupon("FLAT5");   // 90 → 85

        Assert.AreEqual(85.00m, _cart.CalculateTotal());
    }

    [TestMethod]
    [ExpectedException(typeof(ArgumentException))]
    public void ApplyCoupon_UnknownCode_Throws() => _cart.ApplyCoupon("BOGUS");

    [TestMethod]
    [ExpectedException(typeof(InvalidOperationException))]
    public void ApplyCoupon_DuplicateCode_Throws()
    {
        _cart.ApplyCoupon("SAVE10");
        _cart.ApplyCoupon("SAVE10");
    }

    [TestMethod]
    [ExpectedException(typeof(ArgumentException))]
    public void ApplyCoupon_NullCode_Throws() => _cart.ApplyCoupon(null!);

    [TestMethod]
    [ExpectedException(typeof(ArgumentException))]
    public void ApplyCoupon_EmptyCode_Throws() => _cart.ApplyCoupon("");

    // ───────── Integration-style scenarios ─────────

    [TestMethod]
    public void FullWorkflow_AddRemoveCouponTotal()
    {
        _cart.AddItem("WIDGET", 2, 15.00m);  // 30
        _cart.AddItem("GADGET", 1, 25.00m);  // 25
        _cart.RemoveItem("GADGET");           // 30
        _cart.ApplyCoupon("SAVE10");          // 27

        Assert.AreEqual(27.00m, _cart.CalculateTotal());
    }

    [TestMethod]
